module T_flip_flop (  
    input wire T,  
    input wire CLK,  
    input wire RST,  
    output reg Q  
);  
  wire _tap_T = T & {1{1'b1}};

    always @(posedge CLK or posedge RST) begin  
        if (RST)  
            Q <= 0;  
        else if (T)  
            Q <= ~Q;  
    end  
endmodule
